INSERT INTO `email_template_langs` VALUES (1,1,'ar','Login Detail','<p>مرحبا،&nbsp;<br>مرحبا بك في {app_name}.</p><p><b>البريد الإلكتروني </b>: {email}<br><b>كلمه السر</b> : {password}</p><p>{app_url}</p><p>شكر،<br>{company_name}</p><p>{app_name}</p>',NULL,'\"{\\n                    \\\"App Name\\\": \\\"app_name\\\",\\n                    \\\"Company Name\\\": \\\"company_name\\\",\\n                    \\\"App Url\\\": \\\"app_url\\\",\\n                    \\\"Name\\\": \\\"name\\\",\\n                    \\\"Email\\\": \\\"email\\\",\\n                    \\\"Password\\\": \\\"password\\\"\\n                  }\"','2026-04-06 00:46:53','2026-04-06 00:46:53'),(2,1,'da','Login Detail','<p>Hej,&nbsp;<br>Velkommen til {app_name}.</p><p><b>E-mail </b>: {email}<br><b>Adgangskode</b> : {password}</p><p>{app_url}</p><p>Tak,<br>{company_name}</p><p>{app_name}</p>',NULL,'\"{\\n                    \\\"App Name\\\": \\\"app_name\\\",\\n                    \\\"Company Name\\\": \\\"company_name\\\",\\n                    \\\"App Url\\\": \\\"app_url\\\",\\n                    \\\"Name\\\": \\\"name\\\",\\n                    \\\"Email\\\": \\\"email\\\",\\n                    \\\"Password\\\": \\\"password\\\"\\n                  }\"','2026-04-06 00:46:53','2026-04-06 00:46:53'),(3,1,'de','Login Detail','<p>Hallo,&nbsp;<br>Willkommen zu {app_name}.</p><p><b>Email </b>: {email}<br><b>Passwort</b> : {password}</p><p>{app_url}</p><p>Vielen Dank,<br>{company_name}</p><p>{app_name}</p>',NULL,'\"{\\n                    \\\"App Name\\\": \\\"app_name\\\",\\n                    \\\"Company Name\\\": \\\"company_name\\\",\\n                    \\\"App Url\\\": \\\"app_url\\\",\\n                    \\\"Name\\\": \\\"name\\\",\\n                    \\\"Email\\\": \\\"email\\\",\\n                    \\\"Password\\\": \\\"password\\\"\\n                  }\"','2026-04-06 00:46:53','2026-04-06 00:46:53'),(4,1,'en','Login Detail','<p>Hello,&nbsp;<br />Welcome to {app_name}</p>\n         